from flask import Flask, request, jsonify
import logging
from datetime import datetime

app = Flask(__name__)

# Configure logging
logging.basicConfig(filename='application.log', level=logging.INFO)

@app.route('/login', methods=['POST'])
def login():
    data = request.json
    username = data.get('username')
    password = data.get('password')
    email = data.get('email')
    ip_address = request.remote_addr
    user_agent = request.headers.get('User-Agent')

    # Log the login attempt
    log_message = f"Login Attempt - Time: {datetime.now()}, Username: {username}, Email: {email}, IP Address: {ip_address}, User Agent: {user_agent}"
    logging.info(log_message)

    # For demonstration, always return success
    return jsonify({'message': 'Login successful', 'status': 200})

if __name__ == '__main__':
    app.run(debug=True)